const express = require('express');
const session = require('express-session');
const cookieParser = require('cookie-parser');

const app = express();
app.use(express.json());
app.use(cookieParser());
app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true,
}));

// In-memory storage for authorization codes
let authCodes = {};

// User model (simplified)
class User {
  constructor(id, username) {
    this.id = id;
    this.username = username;
  }
}

const users = [
  new User(1, 'john'),
  new User(2, 'jane'),
];

app.get('/authorize', async (req, res) => {
  const clientId = req.query.client_id;
  const redirectUri = req.query.redirect_uri;
  const scope = req.query.scope;

  if (!clientId || !redirectUri || !scope) {
    return res.status(400).send({ error: 'missing_required_parameter' });
  }

  // Find user by username
  const user = users.find((u) => u.username === clientId);

  if (!user) {
    return res.status(401).send({ error: 'invalid_client' });
  }

  // Generate authorization code
  const authCode = Math.random().toString(36).substr(2, 10);
  authCodes[authCode] = { user, redirectUri };

  // Redirect to client with authorization code
  res.redirect(`${redirectUri}?code=${authCode}&state=123`);
});

app.post('/token', async (req, res) => {
  const clientId = req.body.client_id;
  const clientSecret = req.body.client_secret;
  const code = req.body.code;
  const redirectUri = req.body.redirect_uri;

  if (!clientId || !clientSecret || !code || !redirectUri) {
    return res.status(400).send({ error: 'missing_required_parameter' });
  }

  // Verify client credentials
  if (clientId !== 'your-client-id' || clientSecret !== 'your-client-secret') {
    return res.status(401).send({ error: 'invalid_client' });
  }

  // Find authorization code in memory
  const authCode = authCodes[code];

  if (!authCode) {
    return res.status(400).send({ error: 'invalid_grant' });
  }

  // Verify redirect URI matches
  if (redirectUri !== authCode.redirectUri) {
    return res.status(401).send({ error: 'invalid_redirect_uri' });
  }

  // Generate access token
  const accessToken = Math.random().toString(36).substr(2, 10);

  // Return access token to client
  res.send({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
  });
});

const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});